            SortOrder = 4,
            AppRoutes = """["/calendar"]""",
            Tags = """["calendar","quiz"]""",
            ContentJson = """{"passingScore":80,"questionsPerQuiz":8,"shuffleOptions":true,"showExplanationsAfterSubmit":true,"questions":[{"id":"cal1","text":"What are the three views in the Calendar?","options":[{"id":"a","text":"Month, Week, and Day","isCorrect":true},{"id":"b","text":"Timeline, Gantt, and List"},{"id":"c","text":"Daily, Quarterly, and Yearly"},{"id":"d","text":"Board, Table, and Calendar"}],"explanation":"The Calendar has three views — Month, Week, and Day — that you switch with buttons at the top. Each shows the same work at a different level of detail."},{"id":"cal2","text":"You want to see purchase order delivery dates alongside your jobs on the calendar. How do you turn this on?","options":[{"id":"a","text":"Go to Admin, then Calendar Settings, and check 'Show PO Deliveries'"},{"id":"b","text":"Click the Show PO Deliveries button at the top of the calendar","isCorrect":true},{"id":"c","text":"Switch to the Purchase Orders page and turn on calendar view"},{"id":"d","text":"Deliveries are always shown — they can't be turned off"}],"explanation":"The Show PO Deliveries button at the top controls whether delivery dates appear on the calendar. When it's on, the button is highlighted."},{"id":"cal3","text":"In Month view, a day shows three jobs and a '+4 more' note. What does '+4 more' mean?","options":[{"id":"a","text":"4 jobs were recently archived from that date"},{"id":"b","text":"4 more jobs are due that day but are hidden to save space","isCorrect":true},{"id":"c","text":"4 deliveries are expected that day"},{"id":"d","text":"The jobs are 4 or more days past due"}],"explanation":"Month view shows up to 3 jobs per day. When there are more, a '+N more' note appears. Click the day to open Day view and see them all."},{"id":"cal4","text":"A job label shows a red priority flag. What does that mean?","options":[{"id":"a","text":"The job is High priority"},{"id":"b","text":"The job is Critical priority","isCorrect":true},{"id":"c","text":"The job is overdue"},{"id":"d","text":"The job has been flagged for review"}],"explanation":"A red priority flag means Critical priority. High priority jobs show an orange flag instead. Both help you spot important work at a glance."},{"id":"cal5","text":"You're in Week view and want to see full details for Wednesday's jobs. How do you get there?","options":[{"id":"a","text":"Double-click Wednesday's column to expand it"},{"id":"b","text":"Click Wednesday's day heading to open Day view for that date","isCorrect":true},{"id":"c","text":"Hover over Wednesday's column to see the details in a tooltip"},{"id":"d","text":"Right-click and choose 'View Day Details'"}],"explanation":"Clicking a day heading in Week view (or a day in Month view) opens Day view for that date, with full detail including customer, stage, who it's assigned to, and priority."},{"id":"cal6","text":"What does the colored left edge on a job label mean?","options":[{"id":"a","text":"The job's priority (red for Critical, orange for High, and so on)"},{"id":"b","text":"The job's current stage","isCorrect":true},{"id":"c","text":"The track color for the job's board"},{"id":"d","text":"The customer's assigned color"}],"explanation":"Each job label has a colored left edge that matches its current stage. This lets you tell stages apart at a glance without reading the text."},{"id":"cal7","text":"You see a warning marker on a job label. What does it mean?","options":[{"id":"a","text":"The job has unresolved quality issues"},{"id":"b","text":"The job's due date has passed and it still isn't complete","isCorrect":true},{"id":"c","text":"The job is missing required materials"},{"id":"d","text":"The job has no one assigned"}],"explanation":"A warning marker appears on overdue jobs — their due date has passed but they aren't complete. This helps you spot late work at a glance."},{"id":"cal8","text":"How does the track filter at the top of the calendar work?","options":[{"id":"a","text":"It shows only the jobs from one track","isCorrect":true},{"id":"b","text":"It changes the calendar's colors to match the track"},{"id":"c","text":"It switches between different calendar layouts"},{"id":"d","text":"It filters deliveries by the vendor's track"}],"explanation":"The track filter shows only the jobs from one track (Production, R&D, Maintenance, and so on). This lets you focus on one part of the business while planning."},{"id":"cal9","text":"In Day view, what's on a job's detail line?","options":[{"id":"a","text":"Created date, last modified date, and attachment count"},{"id":"b","text":"Customer, stage, who it's assigned to, and priority","isCorrect":true},{"id":"c","text":"Cost estimate, hours logged, and percent complete"},{"id":"d","text":"Part number, quantity ordered, and material type"}],"explanation":"Day view shows the most detail. Each job shows its number, title, and priority on the main line, with a detail line below showing the customer, current stage, who it's assigned to, and its priority."},{"id":"cal10","text":"What happens when you click the Today button?","options":[{"id":"a","text":"It creates a new job due today"},{"id":"b","text":"It jumps back to the current date, keeping whichever view you're in","isCorrect":true},{"id":"c","text":"It switches to Day view for today"},{"id":"d","text":"It highlights every overdue job on the calendar"}],"explanation":"The Today button jumps back to the current date while keeping your current view (Month, Week, or Day). It changes the date you're looking at, not the view."},{"id":"cal11","text":"In Day view, what shows when a date has no jobs or deliveries?","options":[{"id":"a","text":"A blank white space with nothing on it"},{"id":"b","text":"A friendly message that nothing is scheduled","isCorrect":true},{"id":"c","text":"A prompt to create a new job for that date"},{"id":"d","text":"A list of recently completed jobs from nearby dates"}],"explanation":"When a date has nothing scheduled, Day view shows a friendly message rather than blank space."},{"id":"cal12","text":"A delivery on the calendar shows 'PO-2048 · Acme Metals · 5 lines'. What does '5 lines' mean?","options":[{"id":"a","text":"The order has 5 separate delivery dates"},{"id":"b","text":"The order has 5 lines","isCorrect":true},{"id":"c","text":"The order has been revised 5 times"},{"id":"d","text":"5 units are expected in this delivery"}],"explanation":"The line count shows how many lines are on the purchase order. It gives you a quick sense of the delivery's size without opening the full order."},{"id":"cal13","text":"You spot a job due tomorrow and want to move it to the next stage. What happens when you click the job?","options":[{"id":"a","text":"An edit form opens on the calendar so you can change the stage right there"},{"id":"b","text":"It opens the job on the Kanban board, where you can change its stage and edit it","isCorrect":true},{"id":"c","text":"It switches the calendar to Day view for that job's due date"},{"id":"d","text":"It opens a view-only panel — the calendar doesn't link to the board"}],"explanation":"The calendar is view-only. Clicking a job in any view opens it on the Kanban board, already selected, where all editing happens — stage moves, details, and time logging. Clicking empty space in a day opens Day view instead. Delivery labels don't open anything."}]}"""
